mapper.sql:
FROM house_deals hd
INNER JOIN houses h ON h.house_id = hd.house_id
INNER JOIN regions r ON r.region_id = h.region_id
WHERE hd.house_type = 'apartment'
  AND hd.deal_type = 'sale'

  AND hd.lawd_cd = #{condition.lawdCd}


  AND r.sido = #{condition.sido}


  AND r.sigungu = #{condition.sigungu}


  AND h.umd_nm = #{condition.umdNm}


  AND h.apt_nm LIKE CONCAT('%', #{condition.aptName}, '%')


  AND hd.deal_ymd = #{condition.dealYmd}
